	@Test
	public void runTiledAlignerCache() throws IOException {
		try {
			TiledAlignerUtil.runTiledAlignerCache(null, null, null, null, 0, null, false, false);
			fail("Should have thrown an IllegalArgumentException");
		} catch (IllegalArgumentException iae) {}
		
		/*
		 * create a reference file
		 */
		File ref = testFolder.newFile("ref.fa");
		try {
			TiledAlignerUtil.runTiledAlignerCache(ref.getAbsolutePath(), null, null, null, 0, null, false, false);
			fail("Should have thrown an IllegalArgumentException");
		} catch (IllegalArgumentException iae) {}
		
		/*
		 * create sequencesNameMap
		 */
		Map<String, String> sequencesNameMap = new HashMap<>();
		Map<String, List<BLATRecord>> map = TiledAlignerUtil.runTiledAlignerCache(ref.getAbsolutePath(), null, null, sequencesNameMap, 0, null, false, false);
		assertTrue(map.isEmpty());
		
		/*
		 * populate sequencesNameMap
		 */
		sequencesNameMap.put("ABCDABCDABCDABCD", "my_fav_Sequence");
		try {
			map = TiledAlignerUtil.runTiledAlignerCache(ref.getAbsolutePath(), null, null, sequencesNameMap, 0, null, false, false);
			fail("Should have thrown an IllegalArgumentException");
		} catch (IllegalArgumentException iae) {}
		
		/*
		 * create cache - populate
		 */
		TIntObjectMap<int[]> cache = new TIntObjectHashMap<int[]>();
		int [] array = new int[10];
		Arrays.fill(array, 10);
		cache.put(1, array);
		map = TiledAlignerUtil.runTiledAlignerCache(ref.getAbsolutePath(), null, cache, sequencesNameMap, 13, null, false, false);
		assertEquals(1, map.size());
		assertEquals(0, map.values().iterator().next().size());
	}
	
	@Test
	public void useIndexFileIfPresent() throws IOException {
		File fa = testFolder.newFile("test.fa");
		/*
		 * no index so should load default positions - no exception
		 */
		Map<ChrPosition, LongRange> map = TiledAlignerUtil.loadReferenceIndexMap(fa.getAbsolutePath(), null);
        assertFalse(map.isEmpty());
		
		/*
		 * add an index file - should use this rather than default
		 */
		File index = testFolder.newFile("test.fa.fai");
		map = TiledAlignerUtil.loadReferenceIndexMap(fa.getAbsolutePath(), null);
        assertTrue(map.isEmpty());
		
		/*
		 * and finally with the explicit call to the index
		 */
		map = TiledAlignerUtil.loadReferenceIndexMap(fa.getAbsolutePath(), index.getAbsolutePath());
        assertTrue(map.isEmpty());
		
	}
	
	@Test
	public void getAlternatives() {
		String s = "AAAANCCCC";
		List<String> alternativeSequences = TiledAlignerUtil.getAlternativeSequences(s);
		assertEquals(4, alternativeSequences.size());
        assertTrue(alternativeSequences.contains("AAAAACCCC"));
        assertTrue(alternativeSequences.contains("AAAACCCCC"));
        assertTrue(alternativeSequences.contains("AAAAGCCCC"));
        assertTrue(alternativeSequences.contains("AAAATCCCC"));
		
		/*
		 * start of seq
		 */
		s = "NAAAACCCC";
		alternativeSequences = TiledAlignerUtil.getAlternativeSequences(s);
		assertEquals(4, alternativeSequences.size());
        assertTrue(alternativeSequences.contains("AAAAACCCC"));
        assertTrue(alternativeSequences.contains("CAAAACCCC"));
        assertTrue(alternativeSequences.contains("GAAAACCCC"));
        assertTrue(alternativeSequences.contains("TAAAACCCC"));
		
		/*
		 * end of seq
		 */
		s = "AAAACCCCN";
		alternativeSequences = TiledAlignerUtil.getAlternativeSequences(s);
		assertEquals(4, alternativeSequences.size());
        assertTrue(alternativeSequences.contains("AAAACCCCA"));
        assertTrue(alternativeSequences.contains("AAAACCCCC"));
        assertTrue(alternativeSequences.contains("AAAACCCCG"));
        assertTrue(alternativeSequences.contains("AAAACCCCT"));
	}
	
	@Test
	public void getBlocks() {
		String [] swDiffs = new String[] {"","||||||||||",""};
		List<Range<Integer>> ranges = TiledAlignerUtil.getBlockStartPositions(swDiffs);
		assertEquals(1, ranges.size());
		assertEquals(0, ranges.get(0).getMinimum().intValue());
		assertEquals(9, ranges.get(0).getMaximum().intValue());
	}

	@Test
	public void testSplitString() {
		String[] array = TiledAlignerUtil.splitString("chr22_xxx_49157941_xxx_false_xxx_+");
		assertEquals(4, array.length);
		assertEquals("chr22", array[0]);

		array = TiledAlignerUtil.splitString("chr22_xxx_49157941_xxx_false_xxx_+");
		assertEquals(4, array.length);
		assertEquals("chr22", array[0]);

		array = TiledAlignerUtil.splitString("chrUn_KI270448v1_xxx_1_xxx_true_xxx_-");
		assertEquals(4, array.length);
		assertEquals("chrUn_KI270448v1", array[0]);
	}
	
