	@Test
	public void happyWithSequence() {
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCD"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCD"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCDCC"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCDCCCCCCCCCCCCCCCCCCCCCC"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCDCCCCCCCCCCCCCCCCCCCCCCGGGGGGGGGGGGGGGGGGGGGG"));
        assertFalse(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCDCCCCCCCCCCCCCCCCCCCCCCCGGGGGGGGGGGGGGGGGGGGGG"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("ABCCCCCCCCCCCCCCCCCCCCCCDCCCCCCCCCCCCCCCCCCCCCCCGGGGGGGGGGGGGGGGGGGGGGNNNNNNNNNNNNNNNNNNNN"));
        assertTrue(TiledAlignerUtil.doesSequenceHaveMostlySingleBaseRepeats("GAATCGAATTTGGTTGAAAAAGAAATCTAATGTACATTTATAAGAGGCAGATTTAGATTTAAAAAGTCCAGGAAACTTTTAGTTAACAGATAAATTTAGTCAGTTCAACTTATTATAATTTTTGATACATTTGGATGTATTTAACTCTCTATATTTCTGGTTTTCTGTTTATCATGTTATATCTATGTTTATTTCAAGCATTTGTTTAATAGAATGTTTTCTGACTACTCTCATTTTTTTGAAAGTGGTACATTCTTTTTTTTTTTTTTTTTTTTTTTTATGGTG"));
	}
	
